(233, 'updated', 'App\\Models\\ExplosiveChecklist', 4, '{\"id\":4,\"jcr_id\":null,\"type\":\"c\",\"well_no\":\"GGBF\",\"rig\":\"NG-1500-4\",\"logging_unit_no\":\"4995\",\"job_type\":\"PERFORATION\",\"perf_interval\":null,\"date\":\"2025-10-13T18:30:00.000000Z\",\"checklist_data\":[{\"status\":\"1\",\"name\":\"Remove any rig wiring that might contact the cable while rigging up cable\",\"comments\":null},{\"status\":\"1\",\"name\":\"Install the Casing - to Rig Voltage Monitor. Check for residual voltage. Do not process with operations if the value exceeds 0.25V. Investigate the cause and reduce the level to 0.25V\",\"comments\":null},{\"status\":\"1\",\"name\":\"If the residual voltage is less than 0.25V AC-DC, install safety grounding cable between unit, rig and wellhead. Leave the voltage monitor connected between the rig and the casing\",\"comments\":null},{\"status\":\"1\",\"name\":\"Turn off the AC Generator of Truck \\/ Unit.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Engage the Safety Switch to SAFE mode and remove the key. The key shall be in the personal custody of Incharge Logging.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Does the Casing to Rig voltage monitor reads less than 0.25V DC-AC?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Clear all personnel from the line of fire.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Attach the explosives device to the cable. At this time, the Safety key must be in the possession of the Incharge Logging and till the time the tool\\/ perforator is at least 100m below ground level.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Attach the cable to the gun before arming the gun.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Keeping the detonator in Safety Tube, test it with a Safety Meter.\",\"comments\":null},{\"status\":\"1\",\"name\":\"With the detonator in safety tube arm the gun electrically. First connect the ground lead.\",\"comments\":null},{\"status\":\"1\",\"name\":\"With the detonator in safety tube arm the gun electrically. Then connect the central lead.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Arm the gun ballistically last by crimping the detonator to the detonating cord.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Lift the gun and lower it into the well safely and quickly.\",\"comments\":null},{\"status\":\"1\",\"name\":\"After the gun string is at least 100m below the ground level, turn on the power generators etc.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Disengage the safety lock; insert the cable jack to the collar locator socket for depth tie up.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Tie in, position gun and shoot\",\"comments\":null},{\"status\":\"1\",\"name\":\"Switch off the shooting circuit and bring back the cable jack to collar socket and\\/pull up the gun.\",\"comments\":null},{\"status\":\"1\",\"name\":\"While pulling out of the hole. stop at least 100m below the ground level and return cable jack to SAFE mode and remove the key and keep with in-charge Logging.\",\"comments\":null},{\"status\":\"1\",\"name\":\"After any shooting. successful or not and when the gun is at around 30m below ground sea level proceed the same ways ie before running it\",\"comments\":null},{\"status\":\"1\",\"name\":\"On surface, all gun shall be safely relieved of any trapped pressure gases.\",\"comments\":null},{\"status\":\"1\",\"name\":\"If misfired, ensure temp. of gun below 100\\u00b0C and disarm the gun by disconnectng the detonator. First cut the prima cord from the detonator with a shard blade.\",\"comments\":null},{\"status\":\"1\",\"name\":\"If misfired, ensure temp. of gun below 100\\u00b0C and disarm the gun by disconnectng the detonator. Disconnect the central lead and disconnect the ground lead.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Police the area for detonator cord remnants. unused\\/damaged charges etc. And store then in the explosives remnant box and lock.\",\"comments\":null},{\"statu