(722, 'created', 'App\\Models\\ExplosiveChecklist', 15, NULL, '{\"well_no\":\"GND#136\",\"date\":\"2025-11-10T18:30:00.000000Z\",\"logging_unit_no\":\"GJ-16-BS-4995\",\"job_type\":\"PERFORATION\",\"perf_interval\":\"2984-2987M @12SPM\",\"rig\":\"ROM-100-1\",\"checklist_data\":[{\"status\":\"1\",\"name\":\"Has the following sign boards in Hindi, English and regional languages been displayed at appropriate place in the well site area?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Danger Zone, Explosive in use, turn off all radios.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Danger Zone, Explosive in use, turn off all generators.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Danger Zone, Explosive in use, turn off all welding machines.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Have all the arc\\/gas welding machines been turned off?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Have the Radio Transmitters\\/Receivers phone within 300m been turned off?\",\"comments\":null},{\"status\":\"0\",\"name\":\"is there a large radio\\/television station within 4 Km (if yes, contact the Head Logging vase for insturctions)?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Have all generators been turned off?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Has the cathodic protection system been turned off?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Any state electiricity board power connection to SRP within 30m from wellhead has been switched off and ends connection insulated?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Confirm that there is no high tension linne (over ground and underground) in the vicinity of perforation job site. If it exists, has it been disconnected and insulated?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Has the defective rig wiring, if any, been removed?\",\"comments\":null},{\"status\":\"0\",\"name\":\"Is there any warning for sand storm\\/thunder storm> In case of any storm suspend operations till the storm subsides.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Have all opern fires, if any, in the vicinity of the well site been removed?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Has the WLS safety officer visited the site and his recommendations complied with?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Have the Mobile phones been switched off?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Is the well site free from obstacles and slippery areas? (Specially catwalk, logging unit parking place, etc.)\",\"comments\":null},{\"status\":\"1\",\"name\":\"Is the well scrapped throughly after last cementation\\/squeeze perforation job?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Is the well circulated throughly?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Is the well filled with the fluid?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Is the BOP tested? - time when last tested\",\"comments\":null},{\"status\":\"0\",\"name\":\"Whether pressure control equipment is used\",\"comments\":null},{\"status\":null,\"name\":\"Are lubricators and hydraulic pack offs function tested?\",\"comments\":null},{\"status\":null,\"name\":\"Wireline BOP is function tested?\",\"comments\":null},{\"status\":\"0\",\"name\":\"Are there any other hazards coming up in the way of the safe working practices?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Has the logging unit been parked at a safe distance? (to be confirmed by Logging Crew Chief)\",\"comments\":null}],\"type\":\"b\",\"creator_id\":20,\"status\":\"draft\",\"updated_at\":\"2025-11-11T06:25:04.000000Z\",\"created_at\":\"2025-11-11T06:25:04.000000Z\",\"id\":15}', 'http://10.205.59.106/checklists/store/b', '10.207.97.92', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/141.0.0.0 Safari/537.36 Edg/141.0.0.0', 20, '2025-11-11 06:25:04', '2025-11-11 06:25:04');
