INSERT INTO `explosive_checklists` (`id`, `jcr_id`, `type`, `well_no`, `rig`, `logging_unit_no`, `job_type`, `perf_interval`, `date`, `checklist_data`, `status`, `creator_id`, `sign_status`, `created_at`, `updated_at`, `external_sign_status`) VALUES
(2, 640, 'a', 'GGBF', NULL, '4995', NULL, NULL, '2025-10-14', '[{\"status\":\"1\",\"name\":\"Safety tube\",\"comments\":null},{\"status\":\"1\",\"name\":\"Detonator carrying box with proper lock and key\",\"comments\":null},{\"status\":\"1\",\"name\":\"Explosive remanent box with proper lock and key\",\"comments\":null},{\"status\":\"1\",\"name\":\"Casing to rig voltage monitor\",\"comments\":null},{\"status\":\"1\",\"name\":\"Safety meter for testing detonators\",\"comments\":null},{\"status\":\"1\",\"name\":\"Safety grounding device of truck\\/unit with spool and c-clamps\",\"comments\":null},{\"status\":\"1\",\"name\":\"Has the explosive field checklist been taken?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Has the following sign boards in Hindi, English and regional languages taken?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Danger Zone, Explosive in use, turn off all radios.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Danger Zone, Explosive in use, turn off all generators.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Danger Zone, Explosive in use, turn off all welding machines.\",\"comments\":null}]', 'signed', 20, 'fully_signed', '2025-10-14 12:17:29', '2025-10-27 06:54:46', 'pending'),
(3, 640, 'b', 'GGBF', 'NG-1500-4', '4995', 'PERFORATION', '2800.5-2802.5', '2025-10-14', '[{\"status\":\"1\",\"name\":\"Has the following sign boards in Hindi, English and regional languages been displayed at appropriate place in the well site area?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Danger Zone, Explosive in use, turn off all radios.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Danger Zone, Explosive in use, turn off all generators.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Danger Zone, Explosive in use, turn off all welding machines.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Have all the arc\\/gas welding machines been turned off?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Have the Radio Transmitters\\/Receivers phone within 300m been turned off?\",\"comments\":null},{\"status\":\"0\",\"name\":\"is there a large radio\\/television station within 4 Km (if yes, contact the Head Logging vase for insturctions)?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Have all generators been turned off?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Has the cathodic protection system been turned off?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Any state electiricity board power connection to SRP within 30m from wellhead has been switched off and ends connection insulated?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Confirm that there is no high tension linne (over ground and underground) in the vicinity of perforation job site. If it exists, has it been disconnected and insulated?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Has the defective rig wiring, if any, been removed?\",\"comments\":null},{\"status\":\"0\",\"name\":\"Is there any warning for sand storm\\/thunder storm> In case of any storm suspend operations till the storm subsides.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Have all opern fires, if any, in the vicinity of the well site been removed?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Has the WLS safety officer visited the site and his recommendations complied with?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Have the Mobile phones been switched off?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Is the well site free from obstacles and slippery areas? (Specially catwalk, logging unit parking place, etc.)\",\"comments\":null},{\"status\":\"1\",\"name\":\"Is the well scrapped throughly after last cementation\\/squeeze perforation job?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Is the well circulated throughly?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Is the well filled with the fluid?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Is the BOP tested? - time when last tested\",\"comments\":null},{\"status\":\"0\",\"name\":\"Whether pressure control equipment is used\",\"comments\":null},{\"status\":null,\"name\":\"Are lubricators and hydraulic pack offs function tested?\",\"comments\":null},{\"status\":null,\"name\":\"Wireline BOP is function tested?\",\"comments\":null},{\"status\":\"0\",\"name\":\"Are there any other hazards coming up in the way of the safe working practices?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Has the logging unit been parked at a safe distance? (to be confirmed by Logging Crew Chief)\",\"comments\":null}]', 'completed', 20, 'partially_signed', '2025-10-14 12:19:00', '2025-10-27 06:54:46', 'pending'),
(4, 640, 'c', 'GGBF', 'NG-1500-4', '4995', 'PERFORATION', NULL, '2025-10-14', '[{\"status\":\"1\",\"name\":\"Remove any rig wiring that might contact the cable while rigging up cable\",\"comments\":null},{\"status\":\"1\",\"name\":\"Install the Casing - to Rig Voltage Monitor. Check for residual voltage. Do not process with operations if the value exceeds 0.25V. Investigate the cause and reduce the level to 0.25V\",\"comments\":null},{\"status\":\"1\",\"name\":\"If the residual voltage is less than 0.25V AC-DC, install safety grounding cable between unit, rig and wellhead. Leave the voltage monitor connected between the rig and the casing\",\"comments\":null},{\"status\":\"1\",\"name\":\"Turn off the AC Generator of Truck \\/ Unit.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Engage the Safety Switch to SAFE mode and remove the key. The key shall be in the personal custody of Incharge Logging.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Does the Casing to Rig voltage monitor reads less than 0.25V DC-AC?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Clear all personnel from the line of fire.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Attach the explosives device to the cable. At this time, the Safety key must be in the possession of the Incharge Logging and till the time the tool\\/ perforator is at least 100m below ground level.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Attach the cable to the gun before arming the gun.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Keeping the detonator in Safety Tube, test it with a Safety Meter.\",\"comments\":null},{\"status\":\"1\",\"name\":\"With the detonator in safety tube arm the gun electrically. First connect the ground lead.\",\"comments\":null},{\"status\":\"1\",\"name\":\"With the detonator in safety tube arm the gun electrically. Then connect the central lead.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Arm the gun ballistically last by crimping the detonator to the detonating cord.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Lift the gun and lower it into the well safely and quickly.\",\"comments\":null},{\"status\":\"1\",\"name\":\"After the gun string is at least 100m below the ground level, turn on the power generators etc.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Disengage the safety lock; insert the cable jack to the collar locator socket for depth tie up.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Tie in, position gun and shoot\",\"comments\":null},{\"status\":\"1\",\"name\":\"Switch off the shooting circuit and bring back the cable jack to collar socket and\\/pull up the gun.\",\"comments\":null},{\"status\":\"1\",\"name\":\"While pulling out of the hole. stop at least 100m below the ground level and return cable jack to SAFE mode and remove the key and keep with in-charge Logging.\",\"comments\":null},{\"status\":\"1\",\"name\":\"After any shooting. successful or not and when the gun is at around 30m below ground sea level proceed the same ways ie before running it\",\"comments\":null},{\"status\":\"1\",\"name\":\"On surface, all gun shall be safely relieved of any trapped pressure gases.\",\"comments\":null},{\"status\":\"1\",\"name\":\"If misfired, ensure temp. of gun below 100\\u00b0C and disarm the gun by disconnectng the detonator. First cut the prima cord from the detonator with a shard blade.\",\"comments\":null},{\"status\":\"1\",\"name\":\"If misfired, ensure temp. of gun below 100\\u00b0C and disarm the gun by disconnectng the detonator. Disconnect the central lead and disconnect the ground lead.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Police the area for detonator cord remnants. unused\\/damaged charges etc. And store then in the explosives remnant box and lock.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Store all unused detonators in the detonator carving case and lock.\",\"comments\":null}]', 'signed', 20, 'fully_signed', '2025-10-14 12:20:46', '2025-10-27 06:54:46', 'pending'),
