(15, 674, 'b', 'GND#136', 'ROM-100-1', 'GJ-16-BS-4995', 'PERFORATION', '2984-2987M @12SPM', '2025-11-11', '[{\"status\":\"1\",\"name\":\"Has the following sign boards in Hindi, English and regional languages been displayed at appropriate place in the well site area?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Danger Zone, Explosive in use, turn off all radios.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Danger Zone, Explosive in use, turn off all generators.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Danger Zone, Explosive in use, turn off all welding machines.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Have all the arc\\/gas welding machines been turned off?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Have the Radio Transmitters\\/Receivers phone within 300m been turned off?\",\"comments\":null},{\"status\":\"0\",\"name\":\"is there a large radio\\/television station within 4 Km (if yes, contact the Head Logging vase for insturctions)?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Have all generators been turned off?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Has the cathodic protection system been turned off?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Any state electiricity board power connection to SRP within 30m from wellhead has been switched off and ends connection insulated?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Confirm that there is no high tension linne (over ground and underground) in the vicinity of perforation job site. If it exists, has it been disconnected and insulated?\",\"comments\":null},{\"status\":\"1\",\"name\":\"Has the defective rig wiring, if any, been removed?\",\"comments\":null},{\"status\":\"0\",\"name\":\"Is there any warning for sand storm\\/thunder storm> In case of any storm suspend operations till the storm subsides.\",\"comments\":null},{\"status\":\"1\",\"name\":\"Have all opern fires, if any, in the vicinity of the well site been removed?\",\"comments\":null},{\"status\